        private static void ValidateCreateGroupContactProperties(GroupContactDetails groupContactList)
        {
            foreach (var groupContact in groupContactList.Contacts)
            {
                if (string.IsNullOrEmpty(groupContact.Email))
                {
                    throw new ApiException(422, ApiValidationMessages.EmailIdRequired);
                }

                if (!IsValidEmail(groupContact.Email))
                {
                    throw new ApiException(422, ApiValidationMessages.InvalidEmailAddress);
                }

                if (string.IsNullOrEmpty(groupContact.Name))
                {
                    throw new ApiException(422, ApiValidationMessages.GroupContactNameRequired);
                }
            }

            ValidateDirectories(groupContactList.Directories);
        }

        /// <summary>
        /// Validate Email.
        /// </summary>
        /// <param name="email">Email Id.</param>
        /// <returns>True if the email is valid.</returns>
        /// https://docs.microsoft.com/en-us/dotnet/standard/base-types/how-to-verify-that-strings-are-in-valid-email-format
        private static bool IsValidEmail(string email)
        {
            if (string.IsNullOrWhiteSpace(email))
            {
                return false;
            }

            try
            {
                // Normalize the domain
                email = Regex.Replace(
                    email,
                    @"(@)(.+)$",
                    DomainMapper,
                    RegexOptions.None,
                    TimeSpan.FromMilliseconds(200));

                // Examines the domain part of the email and normalizes it.
                string DomainMapper(Match match)
                {
                    // Use IdnMapping class to convert Unicode domain names.
                    var idn = new IdnMapping();

                    // Pull out and process domain name (throws ArgumentException on invalid)
                    var domainName = idn.GetAscii(match.Groups[2].Value);

                    return match.Groups[1].Value + domainName;
                }
            }
            catch (RegexMatchTimeoutException)
            {
                return false;
            }
            catch (ArgumentException)
            {
                return false;
            }

            try
            {
                return Regex.IsMatch(
                    email,
#pragma warning disable SA1118 // Parameter should not span multiple lines
                    @"^(?("")("".+?(?<!\\)""@)|(([0-9a-z]((\.(?!\.))|[-!#\$%&'\*\+/=\?\^`\{\}\|~\w])*)(?<=[0-9a-z])@))"
                    + @"(?(\[)(\[(\d{1,3}\.){3}\d{1,3}\])|(([0-9a-z][-0-9a-z]*[0-9a-z]*\.)+[a-z0-9][\-a-z0-9]{0,22}[a-z0-9]))$",
#pragma warning restore SA1118 // Parameter should not span multiple lines
                    RegexOptions.IgnoreCase,
                    TimeSpan.FromMilliseconds(250));
            }
            catch (RegexMatchTimeoutException)
            {
                return false;
            }
        }

        private static void ValidateDirectories(IEnumerable<string> directories)
        {
            if (directories == null)
            {
                return;
            }

            var list = directories.ToList();
            if (list.Count == 0)
            {
                return;
            }

            if (list.Any(x => string.IsNullOrEmpty(x)))
            {
                throw new ApiException(422, ApiValidationMessages.DirectoriesCannotContainEmptyValues);
            }

            if (list.Count > 5)
            {
                throw new ApiException(422, ApiValidationMessages.MaxFiveDirectoriesAllowed);
            }

            if (list.Any(x => x.Length >= 40 || x.Contains(" ")))
            {
                throw new ApiException(422, ApiValidationMessages.DirectoryMaxLengthAndNoSpaces);
            }

            var duplicates = list.GroupBy(x => x).Where(g => g.Count() > 1).Select(g => g.Key).ToList();
            if (duplicates.Any())
            {
                throw new ApiException(422, ApiValidationMessages.DuplicateDirectoriesFound);
            }

            if (list.Any(x => !System.Text.RegularExpressions.Regex.IsMatch(x, @"^[\p{L}\p{Nd}_]+$")))
            {
                throw new ApiException(422, ApiValidationMessages.DirectoriesInvalidSpecialCharacters);
            }
        }
